        { grpCd : "OP190", compID : "acb_cargoClsCd" }
    ];
    await $c.data.setCommonCode(codeOptions);    

    //unit 천원으로 세팅
    //lc_unit.setValue("02");
    //alert( lc_unit.getValue()  );
    //scwin.lc_unit_onchange();

    const params = {
        sysCd: "ManagementProfitAndLossEBC",
        queryId: "retrieveManagementProfitAndLossCloseYm"
    };
    dma_param.setJSON(params);
    $c.sbm.execute(sbm_closeYm);


    //서브미션 버전조회
 //   scwin.f_LoadVer();
