scwin.ondataload = function() { 
    lc_unit.setSelectedIndex(1);
}

scwin.sbm_closeYm_submitdone = function(e) {
    if (ds_closeYm.getRowCount() < 1) return;
    ed_FromDate.setValue( ds_closeYm.getCellData(0, "col1") );

    scwin.f_LoadVer();
}

scwin.f_LoadVer = function() {
    const params = {
        sysCd: "CommonEBC",
        queryId: "retrieveVersionInfo",
        param1: ed_FromDate.getValue().trim().substr(0,4)+"00"
    };
    dma_param.setJSON(params);
    $c.sbm.execute(sbm_version);
}

scwin.sbm_version_submitdone = function (e) {
    scwin.f_SetFinalVer();
};

//-------------------------------------------------------------------------
// 최종 Ver을 설정
//-------------------------------------------------------------------------
scwin.f_SetFinalVer = function () {
    if (ds_version.getRowCount() < 1) return;

    let index = 0;

    for (let i = 0; i < ds_version.getRowCount(); i++) {
        if (ds_version.getCellData(i, "col3") == DGlobalValue.TRUE) { 
            index = i;
            break;
        }
    }

    lc_version.setSelectedIndex(index);
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([ed_FromDate,ed_sacctDeptCd,lc_version]);
    if (!ret) {
        return false;
    }

    //부서
    dma_searchCharacterEach.set("acctDeptCd", ed_sacctDeptCd.getValue());

    //고객(거래처)
    dma_searchCharacterEach.set("clntNo", ed_sclntNo.getValue());

    //화물구분코드
    //dma_searchCharacterEach.set("cargoClsCd", acb_cargoClsCd.getValue());

    $c.sbm.execute(sbm_searchCharacterEach);
}

scwin.sbm_searchCharacterEach_submitdone = function(e) {

    var dl = ds_CharacterEach;
    for (var i = 0; i < dl.getRowCount(); i++) {
        if (dl.getCellData(i, "teuqty") === "") {
            dl.setCellData(i, "teuqty", 0);
        }
        if (dl.getCellData(i, "tonqty") === "") {
            dl.setCellData(i, "tonqty", 0);
        }
    }

    ds_CharacterEach_org.setJSON( ds_CharacterEach.getAllJSON() );
    scwin.f_changeUnit();

    //총건수
    totCnt.setValue(ds_CharacterEach_org.getRowCount());


    //column style 지정
    for (i = 0; i < ds_CharacterEach.getRowCount(); i++ ) {
        if ( ds_CharacterEach.getCellData(i, "variableCost") > 0 ) {
            gr_CharacterEach.setColumnStyle("variableCost", "text-decoration", "underline");
            gr_CharacterEach.setColumnStyle("variableCost", "cursor", "pointer");
            gr_CharacterEach.setColumnStyle("variableCost", "color", "blue");
        }

        if ( ds_CharacterEach.getCellData(i, "fixedCost") > 0 ) {
            gr_CharacterEach.setColumnStyle("fixedCost", "text-decoration", "underline");
            gr_CharacterEach.setColumnStyle("fixedCost", "cursor", "pointer");
            gr_CharacterEach.setColumnStyle("fixedCost", "color", "blue");
        }
    }

    if( ds_CharacterEach.getRowCount() == 0 ){
		$c.win.alert(MSG_CM_ERR_003);
	}
}

