//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->부서
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function(orgObjCd, orgObjNm, flag,check) {
	let cd, nm, param;

    // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
    if (flag == "ALL") {
        cd = "";
        nm = "";
    } else {
        cd = orgObjCd.getValue();
        nm = orgObjNm.getValue();
    }

	// 부서조회    
    switch (flag) {
        // 조회조건용 수금부서 PopUp 호출(물류 귀속부서만 POPUP에 포함)
        case '1':
            udc_sacctDeptCd.cfCommonPopUp( scwin.udc_sacctDeptCd_callBackFunc,
            cd,nm,"T",null,null,null,null,null,null,null,null,null); 
            break;
        case '2':
            param = scwin.txtCoCd;

            udc_sclntNo.setSelectId("retrieveClntEmpNoList");
            udc_sclntNo.cfCommonPopUp( scwin.udc_sclntNo_callBackFunc ,cd,nm,"T",null,null,null,null,param,null,null,null,null);

            break;
        default:
            $c.win.alert("잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
            break;
    }
};

//-------------------------------------------------------------------------
// udc_sclntNo_callBackFunc (거래처조회 팝업 통합처리)
//-------------------------------------------------------------------------
scwin.udc_sclntNo_callBackFunc = function(rtnList) {

    console.log("▲▲ udc_sclntNo_callBackFunc (거래처조회 팝업 통합처리)")
    console.log("   rtnList ["+rtnList+"]");

	if (rtnList != null ) {
	    if (rtnList[0] == "N/A") {
	        return;
	    }

	    ed_sclntNo.setValue( rtnList[0] );  // 거래처코드
	    ed_sclntNm.setValue( rtnList[1] );  // 거래처명명

        ed_sclntNo.options.hidVal = rtnList[0];
        ed_sclntNm.options.hidVal = rtnList[1];


	    scwin.ed_sclntNo_hidVal = rtnList[0];  // 히든값

	    scwin.txt_clntCrn = rtnList[4]; // 사업자번호
	    //사원거래처일경우 사번셋팅(수정 20060412)

	    //if(ed_mgntEmpNo.Enable==true && rtnList[10]=="EM"){
        if(ed_sclntNo.getDisabled() ==false && rtnList[10]=="EM"){
	        ed_sclntNo.setValue(rtnList[11]);
	        ed_sclntNm.setValue(rtnList[12]);
	        scwin.ed_sclntNo_hidVal = rtnList[11];
	    }
	} else {
        console.log("   리턴 없슴");

	    ed_sclntNo.setValue("");
	    txt_sclntNm.setValue("");
	    scwin.ed_sclntNo_hidVal ="";
	    scwin.txt_clntCrn = "";
	}
};

//-------------------------------------------------------------------------
// 부서조회 팝업 callBackFunc
//-------------------------------------------------------------------------
scwin.udc_sacctDeptCd_callBackFunc = function(rtnList) {
    console.log("▷ udc_sacctDeptCd_callBackFunc (작성부서조회 팝업 callBackFunc)")
    console.log("   rtnList : "+rtnList); 

    scwin.f_resultPopEd(ed_sacctDeptCd,ed_sacctDeptNm,rtnList);
};

//-------------------------------------------------------------------------
//팝업결과
//-------------------------------------------------------------------------
scwin.f_resultPopEd = function(strCd, strNm, rtnList){
    console.log("=== f_resultPopEd (팝업결과)");

    // 2025-11-06 : strCd.s 사용안함

	if (rtnList != null ) {
		if (rtnList[0] == "N/A") return;
			strCd.setValue(rtnList[0]);	// 코드
			strNm.setValue(rtnList[1]);	// 명

            strCd.options.hidVal = rtnList[0];	// HIDDEN 코드값
			strNm.options.hidVal = rtnList[1];	// HIDDEN 코드명

	}else{
	    strCd.setValue( "" );
		strNm.setValue( "" );
        strCd.options.hidVal = "";	// HIDDEN 코드값
		strNm.options.hidVal = "";	// HIDDEN 코드명
	}

};

