scwin.lc_unit_onchange = function (info) {
    scwin.f_changeUnit();
};

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnit = function() {
    let unitValue = lc_unit.getValue();
    let unitAmt = 1;
    if (unitValue == "02") {
        unitAmt = 1000;
    } else if (unitValue == "03") {
        unitAmt = 1000000;
    } else if (unitValue == "04") {
        unitAmt = 100000000;
    }
    scwin.f_changeUnitAmt(unitAmt);
};

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnitAmt = function(unitAmt) {
    if (!ds_CharacterEach_org || ds_CharacterEach_org.getRowCount() === 0) {
        return;
    }

    let calculatedData = ds_CharacterEach_org.getAllJSON();
    const cols = ["sellAmt", "variableCost", "fixedCost", "sellSumAmt"];


    for (let i = 0; i < calculatedData.length; i++) {
        let rowData = calculatedData[i];

        for (const colId of cols) {
            if (rowData.hasOwnProperty(colId)) {
                let originalValue = parseFloat(rowData[colId] || 0);
                rowData[colId] = $c.num.round(originalValue / unitAmt);
            }
        }
    }
    ds_CharacterEach.setJSON(calculatedData);

};

