scwin.gr_CharacterEach_oncellclick = async function (rowIndex, columnIndex, columnId) {

    var variableFixedClsCd = "0";		// 변동비 고정비 선택구분 1:변동비, 2:고정비
		// 고정비값이 0일경우는 리턴
	if ( columnId == "fixedCost" ) {
		if ( ds_CharacterEach.getCellData(rowIndex,"fixedCost") == "0" ) { 
			return;
		}
	}

	// 변동비값이 0일경우는 리턴
	if ( columnId == "variableCost" ) {
		if ( ds_CharacterEach.getCellData(rowIndex,"variableCost") == "0" ) { 
			return;
		}
	}

	if ( (columnId == "variableCost" || columnId == "fixedCost") && ( columnId == "level" != "2") ) {
		if ( columnId == "variableCost" ) {
			variableFixedClsCd = "1";
		} else {
			variableFixedClsCd = "2";
		}

        let data = {
            variableFixedClsCd : variableFixedClsCd
            , fromDate : ed_FromDate.getValue()
            , displayClsCd      : "01"	//물류POPUP Open
            , acctDeptCd    :  ed_sacctDeptCd.getValue()		// 귀속부서
            , clntNo      : ds_CharacterEach.getCellData(rowIndex, "reqClntNo")
            , clntNm      : ds_CharacterEach.getCellData(rowIndex, "reqClntNm")
            , ver           : lc_version.getValue()
            , cargoClsCd      : ds_CharacterEach.getCellData(rowIndex, "transCargoClsCd")
            , cargoClsNm      : ds_CharacterEach.getCellData(rowIndex, "transCargoClsNm")
            , commCd      : ds_CharacterEach.getCellData(rowIndex, "commCd")
            , commNm      : ds_CharacterEach.getCellData(rowIndex, "commNm")
            , vsslCd      : ds_CharacterEach.getCellData(rowIndex, "vsslCd")
            , vsslNm      : ds_CharacterEach.getCellData(rowIndex, "vsslNm")
            , moneyClsCd      : lc_unit.getValue()

        }

        console.log("  before 01_03 (예산실적조회) data ["+ JSON.stringify(data)+"]");

        let win_url = "/ui/ac/co/rsltsmgnt/rsltsanl/co_404_01_07p.xml";

        let opts = {
            id : "smpPop"
            , popupName : "특성별 실적상세조회_물류"
            , modal : true
            , type : "browserPopup"
            , width : 1000
            , height : 500
            , title : "특성별 실적상세조회_물류"
        }

        // var style = "center:yes; dialogwidth:840px; dialogheight:540px; scroll:no; resizable:no; status:yes;";
        // var strPath = "fi_201_01_03p.jsp";
        // var returnValue = window.showModalDialog(strPath, valueObject ,style ) ;

        let returnValue = await $c.win.openPopup(win_url, opts, data);

	}
};

scwin.f_Export = async function(e) {

    if ( await $c.win.confirm("Excel로 다운로드 하시겠습니까?") ) {
//alert(  ("특성실적_물류_" + ed_sacctDeptNm.getValue().trim() + "_"+ ed_FromDate.getValue().trim()+"_"+lc_version.getText()).length );
//var exportFileName = "특성별 실적조회_물류_" + ed_sacctDeptNm.Text.trim() + "_"+ed_FromDate.Text.trim()+"_ver_"+lc_version.BindColVal;
        let sheetTitle = "특성별 실적조회_물류";
        const gridId = gr_CharacterEach;
        const infoArr = [];
        const options = {
            fileName: sheetTitle +"_"+ ed_sacctDeptNm.getValue().trim() + "_"+ ed_FromDate.getValue().trim()+"_ver_"+lc_version.getValue() + ".xlsx",    // + ".xls",
            sheetName: sheetTitle
        };

        $c.data.downloadGridViewExcel(gridId, options, infoArr);
    }   
}
scwin.udc_sacctDeptCd_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_sacctDeptCd,ed_sacctDeptNm ,'1','NM');
};


//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function(orgObjCd, orgObjNm, select_code, flag) {
    // if (!orgObjCd.options) orgObjCd.options = {};
    // if (!orgObjNm.options) orgObjNm.options = {};

    if (flag == "CD") {
        if (orgObjCd.getValue() == orgObjCd.options.hidVal) {
            return;
        } else {
            orgObjNm.setValue("");
        }
    } else {
        if (orgObjNm.getValue() == orgObjNm.options.hidVal) {
            return;
        } else {
            orgObjCd.setValue("");
        }
    }

    if (orgObjCd.getValue().trim() != "" || flag == "NM") {
        if (orgObjNm.getValue().trim() != "" || flag == "CD") {
            orgObjCd.setValue(orgObjCd.getValue().trim());
            orgObjNm.setValue(orgObjNm.getValue().trim());
            scwin.f_openPopUp(orgObjCd, orgObjNm, select_code, "NO");
        }
    } else {
        orgObjNm.setValue("");
        orgObjCd.setValue("");
        orgObjCd.options.hidVal = "";
    }
};
